        done();
    });

    it('test exp of pure imaginary number', function(done) {
        // Test exp() of pure imaginary number (0 + πi)
        // e^(0 + πi) = e^0 * (cos(π) + i*sin(π)) = 1 * (-1 + 0i) = -1 + 0i
        let pure_imaginary = new complex_js(0, Math.PI);
        let result = pure_imaginary.exp();
        assert.approximately(result.re, -1, 1e-10, 'Real part should be -1');
        assert.approximately(result.im, 0, 1e-10, 'Imaginary part should be 0');
        done();
    });

    it('test exp of general complex number', function(done) {
        // Test exp() of general complex number (1 + π/2 i)
        // e^(1 + π/2 i) = e^1 * (cos(π/2) + i*sin(π/2)) = e * (0 + i) = 0 + ei
