    it('test exp of negative real number', function(done) {
        // Test exp() of negative real number (-1 + 0i)
        // e^(-1 + 0i) = e^(-1) * (cos(0) + i*sin(0)) = 1/e * (1 + 0i) = 1/e + 0i
